int counter = 0;
int addBtnPin = 9;
int subBtnPin = 10;
int lastAddState = HIGH;
int lastSubState = HIGH;

// Segment pins: a, b, c, d, e, f, g
int segA = 2, segB = 3, segC = 4, segD = 5, segE = 6, segF = 7, segG = 8;

void setup() {
  pinMode(addBtnPin, INPUT_PULLUP);
  pinMode(subBtnPin, INPUT_PULLUP);
  pinMode(segA, OUTPUT);
  pinMode(segB, OUTPUT);
  pinMode(segC, OUTPUT);
  pinMode(segD, OUTPUT);
  pinMode(segE, OUTPUT);
  pinMode(segF, OUTPUT);
  pinMode(segG, OUTPUT);

  displayDigit(0);
}

void displayDigit(int digit) {
  int a, b, c, d, e, f, g;

  if (digit == 0) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 0;
  } else if (digit == 1) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (digit == 2) {
    a = 1; b = 1; c = 0; d = 1; e = 1; f = 0; g = 1;
  } else if (digit == 3) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 0; g = 1;
  } else if (digit == 4) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 1; g = 1;
  } else if (digit == 5) {
    a = 1; b = 0; c = 1; d = 1; e = 0; f = 1; g = 1;
  } else if (digit == 6) {
    a = 1; b = 0; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (digit == 7) {
    a = 1; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (digit == 8) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (digit == 9) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 1; g = 1;
  }

  digitalWrite(segA, a);
  digitalWrite(segB, b);
  digitalWrite(segC, c);
  digitalWrite(segD, d);
  digitalWrite(segE, e);
  digitalWrite(segF, f);
  digitalWrite(segG, g);
}

void loop() {
  int addState = digitalRead(addBtnPin);
  int subState = digitalRead(subBtnPin);

  // Detect ADD button press (HIGH to LOW transition)
  if (addState == LOW && lastAddState == HIGH) {
    if (counter < 9) {
      counter++;
      displayDigit(counter);
    }
  }

  // Detect SUBTRACT button press (HIGH to LOW transition)
  if (subState == LOW && lastSubState == HIGH) {
    if (counter > 0) {
      counter--;
      displayDigit(counter);
    }
  }

  lastAddState = addState;
  lastSubState = subState;
  delay(50);
}

