void displayDigit(int digit) {
  int a, b, c, d, e, f, g;

  if (digit == 0) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 0;
  } else if (digit == 1) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (digit == 2) {
    a = 1; b = 1; c = 0; d = 1; e = 1; f = 0; g = 1;
  } else if (digit == 3) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 0; g = 1;
  } else if (digit == 4) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 1; g = 1;
  } else if (digit == 5) {
    a = 1; b = 0; c = 1; d = 1; e = 0; f = 1; g = 1;
  } else if (digit == 6) {
    a = 1; b = 0; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (digit == 7) {
    a = 1; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (digit == 8) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (digit == 9) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 1; g = 1;
  }

  digitalWrite(segA, a);
  digitalWrite(segB, b);
  digitalWrite(segC, c);
  digitalWrite(segD, d);
  digitalWrite(segE, e);
  digitalWrite(segF, f);
  digitalWrite(segG, g);
}

void loop() {
  int addState = digitalRead(addBtnPin);
  int subState = digitalRead(subBtnPin);
  int potValue = analogRead(potPin);

  // Map potentiometer (0-1023) to display range (0-9)
  int potDigit = potValue / 102;
  if (potDigit > 9) {
    potDigit = 9;
  }

  // Check if potentiometer moved significantly (hysteresis)
  if (potDigit != lastPotDigit) {
    counter = potDigit;
    lastPotDigit = potDigit;
    displayDigit(counter);
    delay(50);
    return;
  }

  // Button increment (add)
  if (addState == LOW && lastAddState == HIGH) {
    if (counter < 9) {
      counter = counter + 1;
    }
    displayDigit(counter);
  }
  lastAddState = addState;

  // Button decrement (subtract)
  if (subState == LOW && lastSubState == HIGH) {
    if (counter > 0) {
      counter = counter - 1;
    }
    displayDigit(counter);
  }
  lastSubState = subState;

  delay(50);
}
